  ('locality-e3452428-moex-00214', 'locality-e3452428', 'locality-e3452428-moex-111-3a7b2121', 'sub-locality-e3452428-03', NULL, 'single_choice', '政府並非當前公共事務的唯一參與者，取而代之的是跨部門合作之趨勢遞增，下列概念中何者最 能呼應這類現象？', '["公共治理", "管制治理", "公司治理", "全球治理"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:18+00:00", "source_pdf_sha1": "d47a3a8602bd", "answer_pdf_sha1": "d5daa51a0dcf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "302", "s": "0608", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "一般民政"}'::jsonb, NULL),
  ('locality-e3452428-moex-00215', 'locality-e3452428', 'locality-e3452428-moex-111-3a7b2121', 'sub-locality-e3452428-03', NULL, 'single_choice', '我國衛生福利部成立之後，將原屬內政部的社會福利業務移撥至該部的作法，稱為：', '["組織改造", "流程簡化", "人員精簡", "協力治理"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:18+00:00", "source_pdf_sha1": "d47a3a8602bd", "answer_pdf_sha1": "d5daa51a0dcf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "302", "s": "0608", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "一般民政"}'::jsonb, NULL),
  ('locality-e3452428-moex-00216', 'locality-e3452428', 'locality-e3452428-moex-111-3a7b2121', 'sub-locality-e3452428-03', NULL, 'single_choice', '有關我國訂定的「公民與政治權利國際公約及經濟社會文化權利國際公約施行法」，下列敘述何者 錯誤？', '["各級政府機關應依規定執行兩公約相關事項", "具有國內法律的效力", "顯示國際公約對公共行政的影響", "代表我國正式邁入先進國家"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:18+00:00", "source_pdf_sha1": "d47a3a8602bd", "answer_pdf_sha1": "d5daa51a0dcf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "302", "s": "0608", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "一般民政"}'::jsonb, NULL),
  ('locality-e3452428-moex-00217', 'locality-e3452428', 'locality-e3452428-moex-111-3a7b2121', 'sub-locality-e3452428-03', NULL, 'single_choice', '面對公共危機時，官僚常見採取避責（blame avoidance）的行為。有關避責行為的內涵與相關策 略的敘述，下列何者錯誤？', '["避責行為係指政治人物或官僚在面臨危機時，運用策略以降低危機對治理正當性的影響", "政治人物因連任或升遷的考量，傾向避免做出不受歡迎的決策", "民主國家因為重視課責機制才存在避責現象，威權國家則無此現象", "強化透明度有助於減少避責行為的發生 30450、31350"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:18+00:00", "source_pdf_sha1": "d47a3a8602bd", "answer_pdf_sha1": "d5daa51a0dcf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "302", "s": "0608", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "一般民政"}'::jsonb, NULL),
  ('locality-e3452428-moex-00218', 'locality-e3452428', 'locality-e3452428-moex-111-3a7b2121', 'sub-locality-e3452428-03', NULL, 'single_choice', '就美英兩國實施情形觀之，下列何者非屬支持「積極平權措施」（affirmativeaction）的理由？', '["促進社會多元性", "彌補歷史集體錯誤", "矯正制度或文化的偏差", "解決反向歧視帶來的後果"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:18+00:00", "source_pdf_sha1": "d47a3a8602bd", "answer_pdf_sha1": "d5daa51a0dcf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "302", "s": "0608", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "一般民政"}'::jsonb, NULL),
  ('locality-e3452428-moex-00219', 'locality-e3452428', 'locality-e3452428-moex-111-3a7b2121', 'sub-locality-e3452428-03', NULL, 'single_choice', '下列那個解釋符合組織內「穀倉效應」的意思？', '["政府部門能未雨綢繆，預先編列未來的預算", "政府部門之間各自為政，只有垂直的指揮系統，欠缺水平的協調", "政府部門的各個系統如同生產線，串接順暢", "政府部門追求預算極大化，不斷追求擴大機關預算規模"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:18+00:00", "source_pdf_sha1": "d47a3a8602bd", "answer_pdf_sha1": "d5daa51a0dcf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "302", "s": "0608", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "一般民政"}'::jsonb, NULL),
  ('locality-e3452428-moex-00220', 'locality-e3452428', 'locality-e3452428-moex-111-3a7b2121', 'sub-locality-e3452428-03', NULL, 'single_choice', '近年來參與式預算在若干地方政府中大行其道，倘若部分公務人員採取消極不配合或抵制態度， 認為這項改革計畫終有謝幕之一天，這適合以下列何種組織病象形容之？', '["不稀罕效應", "白京生定律", "墨菲定律", "邁爾斯定律"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:18+00:00", "source_pdf_sha1": "d47a3a8602bd", "answer_pdf_sha1": "d5daa51a0dcf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "302", "s": "0608", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "一般民政"}'::jsonb, NULL),
  ('locality-e3452428-moex-00221', 'locality-e3452428', 'locality-e3452428-moex-111-3a7b2121', 'sub-locality-e3452428-03', NULL, 'single_choice', '有關我國六都行政機關的組織設計，下列敘述何者錯誤？', '["一級機關內「局、科、股」是組織垂直分化的象徵", "一級機關中「局、處、委員會」是組織水平分化的象徵", "一級機關的組織規模必然大於二級機關", "一級機關的組織位階必然高於二級機關"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:18+00:00", "source_pdf_sha1": "d47a3a8602bd", "answer_pdf_sha1": "d5daa51a0dcf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "302", "s": "0608", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "一般民政"}'::jsonb, NULL),
  ('locality-e3452428-moex-00222', 'locality-e3452428', 'locality-e3452428-moex-111-3a7b2121', 'sub-locality-e3452428-03', NULL, 'single_choice', '有關柯麥隆（K.S.Cameron）及昆恩（R.E.Quinn）對於組織文化之類型分類，下列敘述何者錯誤？', '["家族型文化強調組織作為家父長制之意象，限制彈性與自主發展", "階層型文化強調正式化與結構化，重視穩定與控制", "創新型文化強調組織的創新開放，重視彈性與自主發展", "市場型文化強調外部焦點與差異性，重視競爭與結果"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:18+00:00", "source_pdf_sha1": "d47a3a8602bd", "answer_pdf_sha1": "d5daa51a0dcf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "302", "s": "0608", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "一般民政"}'::jsonb, NULL),
  ('locality-e3452428-moex-00223', 'locality-e3452428', 'locality-e3452428-moex-111-3a7b2121', 'sub-locality-e3452428-03', NULL, 'single_choice', '有關一般行政機關公務人員任用之敘述，下列何者錯誤？', '["年終考績影響同官等內職等之晉升", "具外國國籍者放棄外國國籍後得再任公務人員", "現職委任第五職等公務人員得權理薦任第七職等職務", "具外國國籍而被撤銷任用的公務人員要追還已支付之俸給"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:18+00:00", "source_pdf_sha1": "d47a3a8602bd", "answer_pdf_sha1": "d5daa51a0dcf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "302", "s": "0608", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "一般民政"}'::jsonb, NULL)
